package com.libredisplay.data.repository

import com.libredisplay.data.api.LibreLinkApiClient
import com.libredisplay.data.api.LibreLinkUpException
import com.libredisplay.data.api.LibreLinkUpHttpException
import com.libredisplay.data.api.NonRetryableLibreLinkUpException
import com.libredisplay.data.model.AppSettings
import com.libredisplay.diagnostics.DiagnosticLogger
import com.libredisplay.diagnostics.DiagnosticStatus
import kotlinx.coroutines.sync.Mutex
import kotlinx.coroutines.sync.withLock
import java.time.Instant
import java.time.ZoneId
import java.time.format.DateTimeFormatter

private const val TAG = "AuthRepository"

class AuthRepository(
    settingsRepository: SettingsRepository? = null,
    private val settingsProvider: (() -> AppSettings)? = null,
    private val apiClient: LibreLinkApiClient = LibreLinkApiClient()
) {

    private var token: String? = null
    private var resolvedRegion: String? = null
    private var accountIdHash: String? = null
    private var lastLoginMs: Long = 0L
    private val loginMutex = Mutex()

    fun currentToken(): String? = token

    fun currentAccountIdHash(): String? = accountIdHash

    fun currentRegion(): String = resolvedRegion ?: loadSettings().region

    suspend fun ensureLoggedIn(force: Boolean = false) {
        loginMutex.withLock {
            if (!force && token != null) return@withLock

            val settings = loadSettings()
            if (settings.email.isBlank() || settings.password.isBlank()) {
                throw LibreLinkUpException("Wpisz dane konta LibreLinkUp, na ktorym widzisz odczyty glukozy obserwowanej osoby.")
            }

            try {
                logLoginAttemptContext(settings)
                DiagnosticLogger.logInfo(TAG, "login attempt region=${settings.region}")
                val result = apiClient.login(
                    region = settings.region,
                    email = settings.email,
                    password = settings.password
                )
                token = result.token
                resolvedRegion = result.region
                accountIdHash = result.accountIdHash
                lastLoginMs = System.currentTimeMillis()
                DiagnosticStatus.setLogin(ok = true)
                DiagnosticStatus.setToken(result.token.isNotBlank())
                DiagnosticLogger.logInfo(TAG, "login success region=$resolvedRegion tokenPrefix=${result.token.take(10)}... accountIdPresent=${!accountIdHash.isNullOrBlank()}")
            } catch (e: LibreLinkUpHttpException) {
                logLoginFailureContext(settings, e)
                DiagnosticLogger.logError(TAG, "login failed HTTP ${e.statusCode} body=${e.responseBody}")
                DiagnosticLogger.logException(TAG, e, "Auth HTTP exception")
                DiagnosticStatus.setLogin(ok = false, detail = "HTTP ${e.statusCode}")
                DiagnosticStatus.setLastError("login HTTP ${e.statusCode}: ${e.responseBody}")
                val responseLower = e.responseBody.lowercase()
                if (responseLower.contains("terms") || responseLower.contains("policy") || responseLower.contains("consent")) {
                    throw LibreLinkUpException("Wymagana jest akceptacja warunkow uslugi lub polityki prywatnosci w oficjalnej aplikacji LibreLinkUp.")
                }
                if (e.statusCode == 429 || e.statusCode == 430) {
                    throw NonRetryableLibreLinkUpException("Serwer LibreLinkUp odrzucil logowanie z powodu zbyt wielu prob. Ponow probe recznie pozniej.", e)
                }
                if (e.statusCode == 401) {
                    throw LibreLinkUpException("Nieprawidlowe dane logowania, niezaakceptowane warunki uslugi albo konto nie ma aktywnego polaczenia LibreLinkUp.")
                }
                throw LibreLinkUpException("Blad logowania do LibreLinkUp (HTTP ${e.statusCode})")
            } catch (e: NonRetryableLibreLinkUpException) {
                DiagnosticLogger.logError(
                    TAG,
                    "login failed NON-RETRYABLE region=${settings.region} emailPrefix=${maskEmail(settings.email)} lastSuccess=${formatLastLoginMs()} message=${e.message.orEmpty()}"
                )
                DiagnosticLogger.logException(TAG, e, "Auth non-retryable exception")
                DiagnosticStatus.setLogin(ok = false, detail = "NON_RETRYABLE")
                DiagnosticStatus.setLastError("login NON_RETRYABLE: ${e.message.orEmpty()}")
                throw e
            } catch (e: LibreLinkUpException) {
                DiagnosticLogger.logError(
                    TAG,
                    "login failed DOMAIN region=${settings.region} emailPrefix=${maskEmail(settings.email)} lastSuccess=${formatLastLoginMs()} message=${e.message.orEmpty()}"
                )
                DiagnosticLogger.logException(TAG, e, "Auth domain exception")
                DiagnosticStatus.setLogin(ok = false, detail = "DOMAIN")
                DiagnosticStatus.setLastError("login DOMAIN: ${e.message.orEmpty()}")
                throw e
            }
        }
    }

    private fun logLoginAttemptContext(settings: AppSettings) {
        DiagnosticLogger.logDebug(
            TAG,
            buildString {
                append("login context region=")
                append(settings.region)
                append(" emailPrefix=")
                append(maskEmail(settings.email))
                append(" lastSuccess=")
                append(formatLastLoginMs())
            }
        )
    }

    private fun logLoginFailureContext(settings: AppSettings, e: LibreLinkUpHttpException) {
        val nowText = formatInstant(Instant.now())
        val lastSuccessText = formatLastLoginMs()
        val sinceLastSuccessMs = if (lastLoginMs > 0L) System.currentTimeMillis() - lastLoginMs else null
        DiagnosticLogger.logError(
            TAG,
            buildString {
                append("login failure context at=")
                append(nowText)
                append(" region=")
                append(settings.region)
                append(" emailPrefix=")
                append(maskEmail(settings.email))
                append(" http=")
                append(e.statusCode)
                append(" lastSuccess=")
                append(lastSuccessText)
                if (sinceLastSuccessMs != null) {
                    append(" sinceLastSuccessMs=")
                    append(sinceLastSuccessMs)
                }
                append(" responseBody=")
                append(maskResponseBody(e.responseBody))
            }
        )
    }

    private fun formatLastLoginMs(): String {
        return if (lastLoginMs > 0L) formatInstant(Instant.ofEpochMilli(lastLoginMs)) else "<never>"
    }

    private fun formatInstant(instant: Instant): String {
        return DateTimeFormatter.ISO_LOCAL_DATE_TIME.withZone(ZoneId.systemDefault()).format(instant)
    }

    private fun maskEmail(email: String): String {
        val trimmed = email.trim()
        if (trimmed.isBlank() || !trimmed.contains("@")) return if (trimmed.isBlank()) "<blank>" else trimmed.take(3) + "..."
        val parts = trimmed.split("@", limit = 2)
        val local = parts[0]
        val domain = parts[1]
        val localPrefix = local.take(2)
        return if (localPrefix.isBlank()) "***@$domain" else "$localPrefix***@$domain"
    }

    private fun maskResponseBody(raw: String): String {
        if (raw.isBlank()) return raw
        var masked = raw
        val jsonSecrets = Regex("(?i)(\"(?:token|accesstoken|jwttoken|password|authorization)\"\\s*:\\s*\")[^\"]*(\")")
        masked = jsonSecrets.replace(masked, "$1***$2")
        val bearerSecrets = Regex("(?i)Bearer\\s+[A-Za-z0-9._-]+")
        masked = bearerSecrets.replace(masked, "Bearer ***")
        return masked
    }

    fun clearSession() {
        token = null
        resolvedRegion = null
        accountIdHash = null
        lastLoginMs = 0L
        DiagnosticStatus.setToken(false)
    }

    private val settingsLoader: () -> AppSettings =
        settingsProvider ?: { settingsRepository?.loadSettings() ?: AppSettings() }

    private fun loadSettings(): AppSettings = settingsLoader()
}

package com.libredisplay.data.repository

import com.libredisplay.data.api.LibreLinkApiClient
import com.libredisplay.data.api.LibreLinkUpException
import com.libredisplay.data.api.LibreLinkUpHttpException
import com.libredisplay.data.api.NonRetryableLibreLinkUpException
import com.libredisplay.data.model.AppSettings
import com.libredisplay.diagnostics.DiagnosticLogger
import com.libredisplay.diagnostics.DiagnosticStatus
import kotlinx.coroutines.sync.Mutex
import kotlinx.coroutines.sync.withLock
import java.time.Instant
import java.time.ZoneId
import java.time.format.DateTimeFormatter

private const val TAG = "AuthRepository"

class AuthRepository(
    settingsRepository: SettingsRepository? = null,
    private val settingsProvider: (() -> AppSettings)? = null,
    private val apiClient: LibreLinkApiClient = LibreLinkApiClient()
) {

    private var token: String? = null
    private var resolvedRegion: String? = null
    private var accountIdHash: String? = null
    private var lastLoginMs: Long = 0L
    private val loginMutex = Mutex()

    fun currentToken(): String? = token

    fun currentAccountIdHash(): String? = accountIdHash

    fun currentRegion(): String = resolvedRegion ?: loadSettings().region

    suspend fun ensureLoggedIn(force: Boolean = false) {
        loginMutex.withLock {
            if (!force && token != null) return@withLock

            val settings = loadSettings()
            if (settings.email.isBlank() || settings.password.isBlank()) {
                throw LibreLinkUpException("Wpisz dane konta LibreLinkUp, na ktorym widzisz odczyty glukozy obserwowanej osoby.")
            }

            try {
                logLoginAttemptContext(settings)
                DiagnosticLogger.logInfo(TAG, "login attempt region=${settings.region}")
                val result = apiClient.login(
                    region = settings.region,
                    email = settings.email,
                    password = settings.password
                )
                token = result.token
                resolvedRegion = result.region
                accountIdHash = result.accountIdHash
                lastLoginMs = System.currentTimeMillis()
                DiagnosticStatus.setLogin(ok = true)
                DiagnosticStatus.setToken(result.token.isNotBlank())
                DiagnosticLogger.logInfo(TAG, "login success region=$resolvedRegion tokenPrefix=${result.token.take(10)}... accountIdPresent=${!accountIdHash.isNullOrBlank()}")
            } catch (e: LibreLinkUpHttpException) {
                logLoginFailureContext(settings, e)
                DiagnosticLogger.logError(TAG, "login failed HTTP ${e.statusCode} body=${e.responseBody}")
                DiagnosticLogger.logException(TAG, e, "Auth HTTP exception")
                DiagnosticStatus.setLogin(ok = false, detail = "HTTP ${e.statusCode}")
                DiagnosticStatus.setLastError("login HTTP ${e.statusCode}: ${e.responseBody}")
                val responseLower = e.responseBody.lowercase()
                if (responseLower.contains("terms") || responseLower.contains("policy") || responseLower.contains("consent")) {
                    throw LibreLinkUpException("Wymagana jest akceptacja warunkow uslugi lub polityki prywatnosci w oficjalnej aplikacji LibreLinkUp.")
                }
                if (e.statusCode == 429 || e.statusCode == 430) {
                    throw NonRetryableLibreLinkUpException("Serwer LibreLinkUp odrzucil logowanie z powodu zbyt wielu prob. Ponow probe recznie pozniej.", e)
                }
                if (e.statusCode == 401) {
                    throw LibreLinkUpException("Nieprawidlowe dane logowania, niezaakceptowane warunki uslugi albo konto nie ma aktywnego polaczenia LibreLinkUp.")
                }
                throw LibreLinkUpException("Blad logowania do LibreLinkUp (HTTP ${e.statusCode})")
            } catch (e: NonRetryableLibreLinkUpException) {
                DiagnosticLogger.logError(
                    TAG,
                    "login failed NON-RETRYABLE region=${settings.region} emailPrefix=${maskEmail(settings.email)} lastSuccess=${formatLastLoginMs()} message=${e.message.orEmpty()}"
                )
                DiagnosticLogger.logException(TAG, e, "Auth non-retryable exception")
                DiagnosticStatus.setLogin(ok = false, detail = "NON_RETRYABLE")
                DiagnosticStatus.setLastError("login NON_RETRYABLE: ${e.message.orEmpty()}")
                throw e
            } catch (e: LibreLinkUpException) {
                DiagnosticLogger.logError(
                    TAG,
                    "login failed DOMAIN region=${settings.region} emailPrefix=${maskEmail(settings.email)} lastSuccess=${formatLastLoginMs()} message=${e.message.orEmpty()}"
                )
                DiagnosticLogger.logException(TAG, e, "Auth domain exception")
                DiagnosticStatus.setLogin(ok = false, detail = "DOMAIN")
                DiagnosticStatus.setLastError("login DOMAIN: ${e.message.orEmpty()}")
                throw e
            }
        }
    }

    private fun logLoginAttemptContext(settings: AppSettings) {
        DiagnosticLogger.logDebug(
            TAG,
            buildString {
                append("login context region=")
                append(settings.region)
                append(" emailPrefix=")
                append(maskEmail(settings.email))
                append(" emailLength=")
                append(settings.email.length)
                append(" passwordLength=")
                append(settings.password.length)
                append(" lastSuccess=")
                append(formatLastLoginMs())
            }
        )
    }

    private fun logLoginFailureContext(settings: AppSettings, e: LibreLinkUpHttpException) {
        val nowText = formatInstant(Instant.now())
        val lastSuccessText = formatLastLoginMs()
        val sinceLastSuccessMs = if (lastLoginMs > 0L) System.currentTimeMillis() - lastLoginMs else null
        DiagnosticLogger.logError(
            TAG,
            buildString {
                append("login failure context at=")
                append(nowText)
                append(" region=")
                append(settings.region)
                append(" emailPrefix=")
                append(maskEmail(settings.email))
                append(" http=")
                append(e.statusCode)
                append(" lastSuccess=")
                append(lastSuccessText)
                if (sinceLastSuccessMs != null) {
                    append(" sinceLastSuccessMs=")
                    append(sinceLastSuccessMs)
                }
                append(" responseBody=")
                append(maskResponseBody(e.responseBody))
            }
        )
    }

    private fun formatLastLoginMs(): String {
        return if (lastLoginMs > 0L) formatInstant(Instant.ofEpochMilli(lastLoginMs)) else "<never>"
    }

    private fun formatInstant(instant: Instant): String {
        return DateTimeFormatter.ISO_LOCAL_DATE_TIME.withZone(ZoneId.systemDefault()).format(instant)
    }

    private fun maskEmail(email: String): String {
        val trimmed = email.trim()
        if (trimmed.isBlank() || !trimmed.contains("@")) return if (trimmed.isBlank()) "<blank>" else trimmed.take(3) + "..."
        val parts = trimmed.split("@", limit = 2)
        val local = parts[0]
        val domain = parts[1]
        val localPrefix = local.take(2)
        return if (localPrefix.isBlank()) "***@$domain" else "$localPrefix***@$domain"
    }

    private fun maskResponseBody(raw: String): String {
        if (raw.isBlank()) return raw
        var masked = raw
        val jsonSecrets = Regex("(?i)(\"(?:token|accesstoken|jwttoken|password|authorization)\"\\s*:\\s*\")[^\"]*(\")")
        masked = jsonSecrets.replace(masked, "$1***$2")
        val bearerSecrets = Regex("(?i)Bearer\\s+[A-Za-z0-9._-]+")
        masked = bearerSecrets.replace(masked, "Bearer ***")
        return masked
    }

    fun clearSession() {
        token = null
        resolvedRegion = null
        accountIdHash = null
        lastLoginMs = 0L
        DiagnosticStatus.setToken(false)
    }

    private val settingsLoader: () -> AppSettings =
        settingsProvider ?: { settingsRepository?.loadSettings() ?: AppSettings() }

    private fun loadSettings(): AppSettings = settingsLoader()
}

package com.libredisplay.data.api
import android.util.Log import com.google.gson.JsonElement import com.google.gson.JsonObject import com.libredisplay.diagnostics.DiagnosticLogger import com.libredisplay.diagnostics.DiagnosticStatus import okhttp3.Interceptor import okhttp3.OkHttpClient import okhttp3.logging.HttpLoggingInterceptor import retrofit2.Response import retrofit2.Retrofit import retrofit2.converter.gson.GsonConverterFactory import java.security.MessageDigest
private const val TAG = "LibreLinkApiClient"
open class LibreLinkApiClient( private val productHeader: String = "llu.android", private val versionHeader: String = "4.17.0" ) {
open suspend fun login(region: String, email: String, password: String): LoginResult { val candidates = regionCandidates(region) var lastError: LibreLinkUpHttpException? = null val loginAttemptId = "${System.currentTimeMillis()}-${Thread.currentThread().id}"
DiagnosticLogger.logInfo( TAG, "login flow start attemptId=$loginAttemptId requestedRegion=${region.uppercase()} email=${maskEmail(email)} candidates=${candidates.joinToString { it.code }}" )
for ((index, candidate) in candidates.withIndex()) { DiagnosticLogger.logDebug( TAG, "login candidate attemptId=$loginAttemptId try=${index + 1}/${candidates.size} region=${candidate.code} baseUrl=${candidate.baseUrl}" ) Log.d( TAG, "login: region=${candidate.code} baseUrl=${candidate.baseUrl} endpoint=/llu/auth/login passwordPresent=${password.isNotBlank()}" ) DiagnosticLogger.logDebug(TAG, "login region=${candidate.code} baseUrl=${candidate.baseUrl} endpoint=/llu/auth/login") val service = createService(candidate.baseUrl) val response = service.login(LoginRequest(email, password)) val status = response.code() val responseBody = response.body() val errorText = runCatching { response.errorBody()?.string().orEmpty() }.getOrDefault("")
Log.d( TAG, "login response: status=$status success=${response.isSuccessful} body=${maskSensitive(responseBody?.toString().orEmpty())} error=${maskSensitive(errorText)}" ) DiagnosticLogger.logDebug(TAG, "login status=$status success=${response.isSuccessful} error=${maskSensitive(errorText)}")
if (response.isSuccessful) { val body = responseBody ?: throw LibreLinkUpException("Brak odpowiedzi z serwera LibreLinkUp")
DiagnosticLogger.logDebug(TAG, "LOGIN RAW RESPONSE: ${maskLoginRawResponse(body.toString())}") logLoginResponseStructure(body)
val apiStatus = extractResponseStatus(body) if (apiStatus != null && apiStatus >= 400) { val lockout = extractInt(body, listOf("data", "data", "lockout")) val interval = extractInt(body, listOf("data", "data", "interval")) val failures = extractInt(body, listOf("data", "data", "failures")) val code = extractInt(body, listOf("data", "code")) val message = extractString(body, listOf("data", "message")) DiagnosticLogger.logError( TAG, "login failed via body.status=$apiStatus endpoint=${candidate.baseUrl} region=${candidate.code}" ) DiagnosticLogger.logError( TAG, "login body-status context attemptId=$loginAttemptId status=$apiStatus code=${code ?: -1} message=${message.orEmpty()} failures=${failures ?: -1} interval=${interval ?: -1} lockout=${lockout ?: -1}" ) throw LibreLinkUpHttpException(apiStatus, body.toString()) }
val apiErrorMessage = extractApiErrorMessage(body) if (isLogicalLoginFailure(apiStatus, apiErrorMessage)) { val statusText = apiStatus?.toString() ?: "<missing>" DiagnosticLogger.logError( TAG, "login logical failure attemptId=$loginAttemptId status=$statusText errorMessage=${apiErrorMessage.orEmpty()}" ) throw NonRetryableLibreLinkUpException(mapLogicalLoginFailureMessage(apiStatus, apiErrorMessage)) }
val token = extractToken(body) if (token == null) { Log.w(TAG, "Login token not found. json=${maskSensitive(body.toString())}") throw NonRetryableLibreLinkUpException("Nie znaleziono tokenu. Dostepne pola: ${getAvailableFields(body)}") }
val userId = extractString(body, listOf("data", "data", "user", "id")) val userCountry = extractString(body, listOf("data", "data", "user", "country")) val userRegion = extractString(body, listOf("data", "data", "user", "region")) ?: extractString(body, listOf("data", "data", "authTicket", "region")) val accountIdHash = userId?.let(::sha256Hex)
DiagnosticLogger.logDebug(TAG, "login data.data.user.id=${userId.orEmpty()}") DiagnosticLogger.logDebug(TAG, "login data.data.user.country=${userCountry.orEmpty()}") DiagnosticLogger.logDebug(TAG, "login data.data.user.region=${userRegion.orEmpty()}") DiagnosticLogger.logDebug(TAG, "login account-id sha256 present=${!accountIdHash.isNullOrBlank()} prefix=${accountIdHash?.take(10).orEmpty()}...")
Log.i( TAG, "Login OK region=${candidate.code} endpoint=${candidate.baseUrl} tokenFound=true tokenPrefix=${tokenPrefix(token)}" ) DiagnosticLogger.logDebug(TAG, "login ok region=${candidate.code} tokenPrefix=${tokenPrefix(token)}") return LoginResult( token = token, region = candidate.code, accountIdHash = accountIdHash, userId = userId, userCountry = userCountry, userRegion = userRegion ) }
val ex = LibreLinkUpHttpException(status, errorText) lastError = ex Log.w( TAG, "Login failed endpoint=${candidate.baseUrl} region=${candidate.code} status=$status" ) DiagnosticLogger.logError( TAG, "login failed endpoint=${candidate.baseUrl} region=${candidate.code} status=$status attemptId=$loginAttemptId try=${index + 1}/${candidates.size} error=${maskSensitive(errorText)}" )
if (status == 430 || status == 429) throw ex }
throw lastError ?: LibreLinkUpException("Logowanie do LibreLinkUp nie powiodlo sie") }
open suspend fun getConnections(region: String, token: String, accountIdHash: String?): Response<JsonObject> { val baseUrl = baseUrlForRegion(region) val endpoint = "/llu/connections"
dlog("Token blank=${token.isBlank()}") dlog("Token length=${token.length}") dlog("Token prefix=${token.take(10)}...") dlog("Account-Id present=${!accountIdHash.isNullOrBlank()} prefix=${accountIdHash?.take(10).orEmpty()}...") dlog("Calling getConnections with Authorization header") DiagnosticStatus.setLastEndpoint(endpoint)
Log.d( TAG, "getConnections: region=$region baseUrl=$baseUrl endpoint=$endpoint tokenPresent=${token.isNotBlank()} tokenPrefix=${tokenPrefix(token)} authorizationSet=${("Bearer $token").startsWith("Bearer ")}" ) DiagnosticLogger.logDebug(TAG, "getConnections region=$region baseUrl=$baseUrl tokenPrefix=${tokenPrefix(token)}")
val response = createService(baseUrl).getConnections("Bearer $token", accountIdHash.orEmpty()) Log.d( TAG, "getConnections response: status=${response.code()} success=${response.isSuccessful} body=${maskSensitive(response.body()?.toString().orEmpty())}" ) if (!response.isSuccessful) { DiagnosticStatus.setGetConnections("HTTP ${response.code()}") DiagnosticLogger.logError(TAG, "getConnections failed HTTP ${response.code()} region=$region endpoint=$endpoint tokenPrefix=${tokenPrefix(token)}") } else { DiagnosticStatus.setGetConnections("OK") } return response }
open suspend fun getLatestGraph(region: String, token: String, patientId: String, accountIdHash: String?): Response<JsonObject> { val baseUrl = baseUrlForRegion(region) val endpoint = "/llu/connections/$patientId/graph"
Log.d(TAG, "Token is blank=${token.isBlank()}") Log.d(TAG, "Token length=${token.length}") Log.d(TAG, "Token prefix=${tokenPrefix(token)}") Log.d(TAG, "Account-Id present=${!accountIdHash.isNullOrBlank()} prefix=${accountIdHash?.take(10).orEmpty()}...") DiagnosticStatus.setLastEndpoint(endpoint)
Log.d( TAG, "getLatestGraph: region=$region baseUrl=$baseUrl endpoint=$endpoint patientId=$patientId tokenPresent=${token.isNotBlank()} tokenPrefix=${tokenPrefix(token)} authorizationSet=${("Bearer $token").startsWith("Bearer ")}" ) DiagnosticLogger.logDebug(TAG, "getLatestGraph region=$region endpoint=$endpoint patientId=$patientId tokenPrefix=${tokenPrefix(token)}")
val response = createService(baseUrl).getLatestGraph("Bearer $token", accountIdHash.orEmpty(), patientId) val status = response.code() if (!response.isSuccessful) { DiagnosticStatus.setGetLatestGraph("HTTP $status") val errorText = runCatching { response.errorBody()?.string().orEmpty() }.getOrDefault("") Log.w( TAG, "getLatestGraph HTTP $status: region=$region endpoint=$endpoint patientId=$patientId error=${maskSensitive(errorText)}" ) DiagnosticLogger.logError(TAG, "getLatestGraph failed HTTP $status region=$region endpoint=$endpoint patientId=$patientId body=${maskSensitive(errorText)}") } else { DiagnosticStatus.setGetLatestGraph("OK") } Log.d( TAG, "getLatestGraph response: status=$status success=${response.isSuccessful} body=${maskSensitive(response.body()?.toString().orEmpty())}" ) return response }
private fun createService(baseUrl: String): LibreLinkUpApiService { val headerInterceptor = Interceptor { chain -> val originalRequest = chain.request() dlog("Authorization BEFORE build = ${maskAuthorization(originalRequest.header("Authorization"))}") val requestBuilder = originalRequest.newBuilder() .header("Accept", "application/json") .header("Content-Type", "application/json") .header("product", productHeader) .header("version", versionHeader) .header("cache-control", "no-cache") .header("connection", "Keep-Alive") .header("User-Agent", "LibreDisplay/1.0 (Android)")
var request = requestBuilder.build() dlog("Authorization AFTER build = ${maskAuthorization(request.header("Authorization"))}")
// Safety net: preserve Authorization if it was present before newBuilder().build(). val authorizationBefore = originalRequest.header("Authorization") if (!authorizationBefore.isNullOrBlank() && request.header("Authorization").isNullOrBlank()) { request = request.newBuilder().header("Authorization", authorizationBefore).build() dlog("Authorization restored from original request") dlog("Authorization AFTER restore = ${maskAuthorization(request.header("Authorization"))}") }
dlog("FINAL REQUEST HEADERS") request.headers.names().sorted().forEach { val value = if (it.equals("Authorization", ignoreCase = true)) { maskAuthorization(request.header(it)) } else { request.header(it) } dlog("$it=$value") }
return@Interceptor chain.proceed(request) }
val networkDebugInterceptor = Interceptor { chain -> val request = chain.request() val headersToLog = listOf( "Authorization", "Accept", "Content-Type", "product", "version", "User-Agent", "cache-control", "connection", "Account-Id", "account-id" )
Log.d(TAG, "=====================") Log.d(TAG, "FINAL REQUEST") Log.d(TAG, "=====================") Log.d(TAG, "URL=${request.url}") Log.d(TAG, "METHOD=${request.method}") Log.d(TAG, "FINAL REQUEST HEADERS") headersToLog.forEach { name -> val value = request.header(name) val display = if (name.equals("Authorization", ignoreCase = true) && !value.isNullOrBlank()) { if (value.startsWith("Bearer ")) "Bearer ${value.removePrefix("Bearer ").take(10)}..." else "${value.take(10)}..." } else { value ?: "<MISSING>" } Log.d(TAG, "$name=$display") } request.headers.names().sorted().forEach { name -> val value = if (name.equals("Authorization", ignoreCase = true)) { maskAuthorization(request.header(name)) } else { request.header(name).orEmpty() } Log.d(TAG, "$name=$value") }
val response = chain.proceed(request) val responseBodyPreview = runCatching { response.peekBody(1024 * 1024).string() } .getOrDefault("<UNAVAILABLE>")
Log.d(TAG, "=====================") Log.d(TAG, "FINAL RESPONSE") Log.d(TAG, "=====================") Log.d(TAG, "status=${response.code}") Log.d(TAG, "headers=") response.headers.names().sorted().forEach { name -> Log.d(TAG, "$name=${response.header(name).orEmpty()}") } Log.d(TAG, "body=$responseBodyPreview")
return@Interceptor response }
val logging = HttpLoggingInterceptor().apply { level = HttpLoggingInterceptor.Level.BASIC }
val client = OkHttpClient.Builder() .addInterceptor(headerInterceptor) .addInterceptor(logging) .addInterceptor(networkDebugInterceptor) .build()
return Retrofit.Builder() .baseUrl(baseUrl) .client(client) .addConverterFactory(GsonConverterFactory.create()) .build() .create(LibreLinkUpApiService::class.java) }
private fun baseUrlForRegion(regionCode: String): String = when (regionCode.uppercase()) { "EU2" -> "https://api-eu2.libreview.io/" "US" -> "https://api-us.libreview.io/" "DE" -> "https://api-de.libreview.io/" "FR" -> "https://api-fr.libreview.io/" else -> "https://api-eu.libreview.io/" }
private fun regionCandidates(regionCode: String): List<RegionCandidate> { return when (regionCode.uppercase()) { "EU" -> listOf( RegionCandidate("EU", "https://api-eu.libreview.io/"), RegionCandidate("EU2", "https://api-eu2.libreview.io/") ) else -> listOf(RegionCandidate(regionCode.uppercase(), baseUrlForRegion(regionCode))) } }
private fun extractToken(body: JsonObject): String? { val probePaths = listOf( listOf("data", "authTicket", "token"), listOf("data", "data", "authTicket", "token"), listOf("data", "token"), listOf("token") )
val traces = probePaths.map { path -> readPathTrace(body, path) } traces.forEach { t -> DiagnosticLogger.logDebug(TAG, "READ: ${t.path} -> ${if (t.found) "SUCCESS" else "NULL"}${t.details}") }
val configuredPath = "root.data.data.authTicket.token" val configured = traces.firstOrNull { it.path == configuredPath } if (configured?.found == true) { return configured.value }
val failed = traces.joinToString(separator = "; ") { "${it.path}=${if (it.found) "FOUND" else "NOT_FOUND"}" } DiagnosticLogger.logError(TAG, "FAILED TOKEN PATHS: $failed") return null }
private fun logLoginResponseStructure(body: JsonObject) { try { val rootKeys = body.keySet().sorted() val data = getNodeAtPath(body, listOf("data")) val dataData = getNodeAtPath(body, listOf("data", "data")) val dataDataData = getNodeAtPath(body, listOf("data", "data", "data")) val authTicket = getNodeAtPath(body, listOf("data", "data", "authTicket")) val token = getNodeAtPath(body, listOf("data", "data", "authTicket", "token")) val user = getNodeAtPath(body, listOf("data", "data", "user")) val actualAuthTicketPath = if (authTicket?.isJsonObject == true) "data.data.authTicket" else "<not found>" val actualTokenPath = if (token?.isJsonPrimitive == true && token.asJsonPrimitive.isString) "data.data.authTicket.token" else "<not found>" val actualUserPath = if (user?.isJsonObject == true) "data.data.user" else "<not found>"
Log.d(TAG, "Login response keys: root=$rootKeys data=${keyList(data)} data.data=${keyList(dataData)} data.data.data=${keyList(dataDataData)} authTicket=${keyList(authTicket)} user=${keyList(user)}") DiagnosticLogger.logDebug(TAG, "login keys root=$rootKeys") DiagnosticLogger.logDebug(TAG, "login keys data=${keyList(data)}") DiagnosticLogger.logDebug(TAG, "login keys data.data=${keyList(dataData)}") DiagnosticLogger.logDebug(TAG, "login keys data.data.data=${keyList(dataDataData)}") DiagnosticLogger.logDebug(TAG, "login authTicket actualPath=$actualAuthTicketPath keys=${keyList(authTicket)} present=${authTicket?.isJsonObject == true}") DiagnosticLogger.logDebug(TAG, "login token actualPath=$actualTokenPath present=${token?.isJsonPrimitive == true && token.asJsonPrimitive.isString}") DiagnosticLogger.logDebug(TAG, "login user actualPath=$actualUserPath keys=${keyList(user)} present=${user?.isJsonObject == true}")
// Full structural dump (depth-limited) so parser regressions can be diagnosed without guessing paths. DiagnosticLogger.logDebug(TAG, "login tree begin") dumpJsonTree(path = "root", element = body, level = 0, maxDepth = 5) DiagnosticLogger.logDebug(TAG, "login tree end")
DiagnosticLogger.logDebug(TAG, "login full-path tree begin") dumpJsonTreePaths(path = "root", element = body, level = 0, maxDepth = 5) DiagnosticLogger.logDebug(TAG, "login full-path tree end")
val tokenLikeFields = mutableListOf<FoundField>() findAllMatchingKeys( element = body, currentPath = "root", targetKeys = setOf("token", "authTicket", "ticket", "jwt", "accessToken", "auth", "bearer", "authorization"), out = tokenLikeFields ) if (tokenLikeFields.isEmpty()) { DiagnosticLogger.logDebug(TAG, "login token-search FOUND: <none>") } else { tokenLikeFields.sortedBy { it.path }.forEach { field -> val meta = buildString { append("type=${field.type}") if (field.length != null) append(" length=${field.length}") if (!field.prefix.isNullOrBlank()) append(" prefix=${field.prefix}") } DiagnosticLogger.logDebug(TAG, "FOUND TOKEN-LIKE FIELD path=${field.path} $meta") } }
val userLikeFields = mutableListOf<FoundField>() findAllMatchingKeys( element = body, currentPath = "root", targetKeys = setOf("user", "authTicket", "patient", "connections"), out = userLikeFields ) if (userLikeFields.isEmpty()) { DiagnosticLogger.logDebug(TAG, "login entity-search FOUND: <none>") } else { userLikeFields.sortedBy { it.path }.forEach { field -> DiagnosticLogger.logDebug(TAG, "FOUND ENTITY FIELD path=${field.path} type=${field.type}") } } } catch (e: Exception) { Log.e(TAG, "Error logging response structure", e) } }
private data class FoundField( val path: String, val type: String, val length: Int? = null, val prefix: String? = null )
private data class ReadTrace( val path: String, val found: Boolean, val value: String? = null, val details: String = "" )
private fun readPathTrace(body: JsonObject, path: List<String>): ReadTrace { var current: JsonElement = body val printablePath = "root.${path.joinToString(".")}" for (key in path) { if (!current.isJsonObject) { return ReadTrace(printablePath, found = false, details = " (encountered non-object before '$key')") } val next = current.asJsonObject.get(key) ?: return ReadTrace(printablePath, found = false) current = next } if (current.isJsonPrimitive && current.asJsonPrimitive.isString) { val value = current.asString val prefix = if (value.isNotBlank()) "${value.take(10)}..." else "" return ReadTrace(printablePath, found = true, value = value, details = " (type=String length=${value.length} prefix=$prefix)") } return ReadTrace(printablePath, found = false, details = " (value not String)") }
private fun dumpJsonTree(path: String, element: JsonElement, level: Int, maxDepth: Int) { val indent = " ".repeat(level) if (level >= maxDepth) { DiagnosticLogger.logDebug(TAG, "$indent$path -> <max-depth>") return }
when { element.isJsonObject -> { val obj = element.asJsonObject DiagnosticLogger.logDebug(TAG, "$indent$path -> object keys=${obj.keySet().sorted()}") obj.entrySet().sortedBy { it.key }.forEach { (key, value) -> dumpJsonTree(path = "$path.$key", element = value, level = level + 1, maxDepth = maxDepth) } } element.isJsonArray -> { val array = element.asJsonArray DiagnosticLogger.logDebug(TAG, "$indent$path -> array size=${array.size()}") val previewCount = minOf(3, array.size()) for (i in 0 until previewCount) { dumpJsonTree(path = "$path[$i]", element = array[i], level = level + 1, maxDepth = maxDepth) } if (array.size() > previewCount) { DiagnosticLogger.logDebug(TAG, "$indent$path[...] -> ${array.size() - previewCount} more items") } } else -> { val type = if (element.isJsonPrimitive) { val p = element.asJsonPrimitive when { p.isString -> "string" p.isNumber -> "number" p.isBoolean -> "boolean" else -> "primitive" } } else if (element.isJsonNull) { "null" } else { "value" } DiagnosticLogger.logDebug(TAG, "$indent$path -> $type") } } }
private fun dumpJsonTreePaths(path: String, element: JsonElement, level: Int, maxDepth: Int) { if (level >= maxDepth) { DiagnosticLogger.logDebug(TAG, "$path") return } DiagnosticLogger.logDebug(TAG, path) when { element.isJsonObject -> { element.asJsonObject.entrySet().sortedBy { it.key }.forEach { (key, value) -> dumpJsonTreePaths(path = "$path.$key", element = value, level = level + 1, maxDepth = maxDepth) } } element.isJsonArray -> { val arr = element.asJsonArray val preview = minOf(3, arr.size()) for (i in 0 until preview) { dumpJsonTreePaths(path = "$path[$i]", element = arr[i], level = level + 1, maxDepth = maxDepth) } } } }
private fun findAllMatchingKeys( element: JsonElement, currentPath: String, targetKeys: Set<String>, out: MutableList<FoundField> ) { if (element.isJsonObject) { val obj = element.asJsonObject obj.entrySet().forEach { (key, value) -> val nextPath = "$currentPath.$key" if (targetKeys.any { it.equals(key, ignoreCase = true) }) { out += FoundField( path = nextPath, type = describeType(value), length = value.takeIf { it.isJsonPrimitive && it.asJsonPrimitive.isString }?.asString?.length, prefix = value.takeIf { it.isJsonPrimitive && it.asJsonPrimitive.isString }?.asString?.take(10)?.plus("...") ) } findAllMatchingKeys(value, nextPath, targetKeys, out) } } else if (element.isJsonArray) { element.asJsonArray.forEachIndexed { index, item -> findAllMatchingKeys(item, "$currentPath[$index]", targetKeys, out) } } }
private fun describeType(element: JsonElement): String { if (element.isJsonObject) return "Object" if (element.isJsonArray) return "Array" if (!element.isJsonPrimitive) return "Unknown" val p = element.asJsonPrimitive return when { p.isString -> "String" p.isNumber -> "Number" p.isBoolean -> "Boolean" else -> "Primitive" } }
private fun getNodeAtPath(body: JsonObject, path: List<String>): JsonElement? { var current: JsonElement = body for (key in path) { if (!current.isJsonObject) return null current = current.asJsonObject.get(key) ?: return null } return current }
private fun extractString(body: JsonObject, path: List<String>): String? { var current: JsonElement = body for (key in path) { if (!current.isJsonObject) return null current = current.asJsonObject.get(key) ?: return null } return if (current.isJsonPrimitive && current.asJsonPrimitive.isString) current.asString else null }
private fun getAvailableFields(body: JsonObject): String { return try { val fields = mutableListOf<String>()
// Root level fields body.keySet().forEach { key -> val value = body.get(key) fields.add(if (value.isJsonObject) "$key{...}" else key) }
// Try to get nested fields from data val dataElement = body.get("data") if (dataElement != null) { if (dataElement.isJsonObject) { dataElement.asJsonObject.keySet().forEach { key -> val value = dataElement.asJsonObject.get(key) fields.add(if (value.isJsonObject) "data.$key{...}" else "data.$key") } val payload = dataElement.asJsonObject.get("data") if (payload != null && payload.isJsonObject) { payload.asJsonObject.keySet().forEach { key -> val value = payload.asJsonObject.get(key) fields.add(if (value.isJsonObject) "data.data.$key{...}" else "data.data.$key") } val nestedPayload = payload.asJsonObject.get("data") if (nestedPayload != null && nestedPayload.isJsonObject) { nestedPayload.asJsonObject.keySet().forEach { key -> val value = nestedPayload.asJsonObject.get(key) fields.add(if (value.isJsonObject) "data.data.data.$key{...}" else "data.data.data.$key") } } } } else if (dataElement.isJsonArray) { fields.add("data[]") val firstObj = dataElement.asJsonArray.firstOrNull { it.isJsonObject } if (firstObj != null) { firstObj.asJsonObject.keySet().forEach { key -> fields.add("data[].$key") } } } }
fields.joinToString(", ") } catch (e: Exception) { "unknown" } }
private fun keyList(element: JsonElement?): List<String> { if (element == null) return emptyList() return when { element.isJsonObject -> element.asJsonObject.keySet().sorted() element.isJsonArray -> { val firstObject = element.asJsonArray.firstOrNull { it.isJsonObject } if (firstObject != null) { firstObject.asJsonObject.keySet().sorted() } else { emptyList() } } else -> emptyList() } }
private fun tokenPrefix(token: String): String = if (token.isBlank()) "" else "${token.take(10)}..."
private fun dlog(message: String) { Log.d(TAG, message) DiagnosticLogger.logDebug(TAG, message) }
private fun maskAuthorization(value: String?): String { if (value.isNullOrBlank()) return "<MISSING>" return if (value.startsWith("Bearer ")) { "Bearer ${value.removePrefix("Bearer ").take(10)}..." } else { "${value.take(10)}..." } }
private fun sha256Hex(value: String): String { val digest = MessageDigest.getInstance("SHA-256").digest(value.toByteArray(Charsets.UTF_8)) return digest.joinToString(separator = "") { byte -> "%02x".format(byte) } }
private fun maskEmail(email: String): String { val trimmed = email.trim() if (trimmed.isBlank() || !trimmed.contains("@")) return if (trimmed.isBlank()) "<blank>" else trimmed.take(3) + "..." val parts = trimmed.split("@", limit = 2) val localPrefix = parts[0].take(2) return if (localPrefix.isBlank()) "***@${parts[1]}" else "$localPrefix***@${parts[1]}" }
private fun maskSensitive(raw: String): String { if (raw.isBlank()) return raw var masked = raw val jsonSecrets = Regex("(?i)(\"(?:token|accesstoken|jwttoken|password|authorization)\"\\s*:\\s*\")[^\"]*(\")") masked = jsonSecrets.replace(masked, "$1***$2") val bearerSecrets = Regex("(?i)Bearer\\s+[A-Za-z0-9._-]+") masked = bearerSecrets.replace(masked, "Bearer ***") return masked }
private fun maskLoginRawResponse(raw: String): String { if (raw.isBlank()) return raw var masked = raw val tokenAndPassword = Regex("(?i)(\"(?:token|password)\"\\s*:\\s*\")[^\"]*(\")") masked = tokenAndPassword.replace(masked, "$1***MASKED***$2") return masked }
private fun extractResponseStatus(body: JsonObject): Int? { val rawStatus = body.get("status") ?: return null if (!rawStatus.isJsonPrimitive) return null val primitive = rawStatus.asJsonPrimitive return when { primitive.isNumber -> primitive.asInt primitive.isString -> primitive.asString.toIntOrNull() else -> null } }
private fun extractInt(body: JsonObject, path: List<String>): Int? { var current: JsonElement = body for (key in path) { if (!current.isJsonObject) return null current = current.asJsonObject.get(key) ?: return null } if (!current.isJsonPrimitive) return null val p = current.asJsonPrimitive return when { p.isNumber -> p.asInt p.isString -> p.asString.toIntOrNull() else -> null } }
private fun extractApiErrorMessage(body: JsonObject): String? { return extractString(body, listOf("error", "message")) ?: extractString(body, listOf("data", "message")) ?: extractString(body, listOf("message")) }
private fun isLogicalLoginFailure(apiStatus: Int?, apiErrorMessage: String?): Boolean { val normalizedMessage = apiErrorMessage?.trim().orEmpty() if (apiStatus != null && apiStatus !in setOf(0, 1, 200)) return true if (normalizedMessage.isBlank()) return false return !setOf("ok", "success").contains(normalizedMessage.lowercase()) }
private fun mapLogicalLoginFailureMessage(apiStatus: Int?, apiErrorMessage: String?): String { val message = apiErrorMessage?.trim().orEmpty() val lower = message.lowercase() return when { lower.contains("incorrect username/password") || lower.contains("invalid") || lower.contains("wrong") -> { "Nieprawidlowe dane logowania LibreLinkUp. Sprawdz email i haslo." } lower.contains("locked") || lower.contains("lockout") || lower.contains("too many") -> { "Serwer LibreLinkUp odrzucil logowanie z powodu zbyt wielu prob. Ponow probe recznie pozniej." } else -> { "Logowanie odrzucone przez API LibreLinkUp (status=${apiStatus ?: -1}, message=${if (message.isBlank()) "<brak>" else message})." } } }
// Public method for testing fun extractTokenForTest(body: JsonObject): String? = extractToken(body)
// Public method for testing fun extractResponseStatusForTest(body: JsonObject): Int? = extractResponseStatus(body) }
data class LoginResult( val token: String, val region: String, val accountIdHash: String? = null, val userId: String? = null, val userCountry: String? = null, val userRegion: String? = null )
data class RegionCandidate( val code: String, val baseUrl: String )

package com.libredisplay.data.api
import android.util.Log import com.google.gson.JsonElement import com.google.gson.JsonObject import com.libredisplay.diagnostics.DiagnosticLogger import com.libredisplay.diagnostics.DiagnosticStatus import okhttp3.Interceptor import okhttp3.OkHttpClient import okhttp3.logging.HttpLoggingInterceptor import retrofit2.Response import retrofit2.Retrofit import retrofit2.converter.gson.GsonConverterFactory import java.security.MessageDigest
private const val TAG = "LibreLinkApiClient"
open class LibreLinkApiClient( private val productHeader: String = "llu.android", private val versionHeader: String = "4.17.0" ) {
companion object { private val loginHistoryLock = Any() private val loginRequestHistory: MutableList<String> = mutableListOf() private var seenIncorrectUsernamePassword: Boolean = false private var seenHttp430AfterIncorrectReported: Boolean = false }
open suspend fun login(region: String, email: String, password: String): LoginResult { val candidates = regionCandidates(region) var lastError: LibreLinkUpHttpException? = null val loginAttemptId = "${System.currentTimeMillis()}-${Thread.currentThread().id}"
DiagnosticLogger.logInfo( TAG, "login flow start attemptId=$loginAttemptId requestedRegion=${region.uppercase()} email=${maskEmail(email)} candidates=${candidates.joinToString { it.code }}" )
for ((index, candidate) in candidates.withIndex()) { DiagnosticLogger.logDebug( TAG, "login candidate attemptId=$loginAttemptId try=${index + 1}/${candidates.size} region=${candidate.code} baseUrl=${candidate.baseUrl}" ) Log.d( TAG, "login: region=${candidate.code} baseUrl=${candidate.baseUrl} endpoint=/llu/auth/login passwordPresent=${password.isNotBlank()}" ) DiagnosticLogger.logDebug(TAG, "login region=${candidate.code} baseUrl=${candidate.baseUrl} endpoint=/llu/auth/login") val endpoint = "/llu/auth/login" val request = LoginRequest(email = email, password = password) val requestBodyMaskedPassword = toLoginRequestJson(request, maskPassword = true, maskEmailValue = false) val requestBodyMaskedForLogs = toLoginRequestJson(request, maskPassword = true, maskEmailValue = true)
DiagnosticLogger.logDebug(TAG, "LOGIN REQUEST BEGIN") DiagnosticLogger.logDebug(TAG, "email masked=${maskEmail(email)}") DiagnosticLogger.logDebug(TAG, "emailLength=${email.length}") DiagnosticLogger.logDebug(TAG, "passwordLength=${password.length}") DiagnosticLogger.logDebug(TAG, "region=${candidate.code}") DiagnosticLogger.logDebug(TAG, "baseUrl=${candidate.baseUrl}") DiagnosticLogger.logDebug(TAG, "endpoint=$endpoint") DiagnosticLogger.logDebug(TAG, "LOGIN REQUEST BODY (password masked): $requestBodyMaskedPassword") DiagnosticLogger.logDebug(TAG, "LOGIN REQUEST BODY (safe logs): $requestBodyMaskedForLogs") DiagnosticLogger.logDebug( TAG, "LOGIN REQUEST SERIALIZATION class=${LoginRequest::class.java.name} jsonFieldNames=[email,password] payload=$requestBodyMaskedPassword" )
appendLoginHistory( "REQUEST attemptId=$loginAttemptId try=${index + 1}/${candidates.size} region=${candidate.code} baseUrl=${candidate.baseUrl} endpoint=$endpoint emailMasked=${maskEmail(email)} emailLength=${email.length} passwordLength=${password.length} body=$requestBodyMaskedPassword" )
val service = createService(candidate.baseUrl) val response = service.login(request) val status = response.code() val responseBody = response.body() val errorText = runCatching { response.errorBody()?.string().orEmpty() }.getOrDefault("") val responseBodyText = responseBody?.toString().orEmpty() val responseBodyForLog = if (responseBodyText.isNotBlank()) responseBodyText else errorText
DiagnosticLogger.logDebug(TAG, "LOGIN RESPONSE HTTP code=$status") DiagnosticLogger.logDebug(TAG, "LOGIN RESPONSE BODY: ${maskLoginRawResponse(responseBodyForLog)}") appendLoginHistory( "RESPONSE attemptId=$loginAttemptId try=${index + 1}/${candidates.size} http=$status body=${maskLoginRawResponse(responseBodyForLog)}" )
Log.d( TAG, "login response: status=$status success=${response.isSuccessful} body=${maskSensitive(responseBodyText)} error=${maskSensitive(errorText)}" ) DiagnosticLogger.logDebug(TAG, "login status=$status success=${response.isSuccessful} error=${maskSensitive(errorText)}")
if (responseBodyForLog.contains("incorrect username/password", ignoreCase = true)) { markSeenIncorrectUsernamePassword(loginAttemptId) } if (status == 430) { maybeReportLoginStateChanged(loginAttemptId) }
if (response.isSuccessful) { val body = responseBody ?: throw LibreLinkUpException("Brak odpowiedzi z serwera LibreLinkUp")
DiagnosticLogger.logDebug(TAG, "LOGIN RAW RESPONSE: ${maskLoginRawResponse(body.toString())}") logLoginResponseStructure(body)
val apiStatus = extractResponseStatus(body) if (apiStatus != null && apiStatus >= 400) { val lockout = extractInt(body, listOf("data", "data", "lockout")) val interval = extractInt(body, listOf("data", "data", "interval")) val failures = extractInt(body, listOf("data", "data", "failures")) val code = extractInt(body, listOf("data", "code")) val message = extractString(body, listOf("data", "message")) DiagnosticLogger.logError( TAG, "login failed via body.status=$apiStatus endpoint=${candidate.baseUrl} region=${candidate.code}" ) DiagnosticLogger.logError( TAG, "login body-status context attemptId=$loginAttemptId status=$apiStatus code=${code ?: -1} message=${message.orEmpty()} failures=${failures ?: -1} interval=${interval ?: -1} lockout=${lockout ?: -1}" ) throw LibreLinkUpHttpException(apiStatus, body.toString()) }
val apiErrorMessage = extractApiErrorMessage(body) if (isLogicalLoginFailure(apiStatus, apiErrorMessage)) { val statusText = apiStatus?.toString() ?: "<missing>" DiagnosticLogger.logError( TAG, "login logical failure attemptId=$loginAttemptId status=$statusText errorMessage=${apiErrorMessage.orEmpty()}" ) throw NonRetryableLibreLinkUpException(mapLogicalLoginFailureMessage(apiStatus, apiErrorMessage)) }
val token = extractToken(body) if (token == null) { Log.w(TAG, "Login token not found. json=${maskSensitive(body.toString())}") throw NonRetryableLibreLinkUpException("Nie znaleziono tokenu. Dostepne pola: ${getAvailableFields(body)}") }
val userId = extractString(body, listOf("data", "data", "user", "id")) val userCountry = extractString(body, listOf("data", "data", "user", "country")) val userRegion = extractString(body, listOf("data", "data", "user", "region")) ?: extractString(body, listOf("data", "data", "authTicket", "region")) val accountIdHash = userId?.let(::sha256Hex)
DiagnosticLogger.logDebug(TAG, "login data.data.user.id=${userId.orEmpty()}") DiagnosticLogger.logDebug(TAG, "login data.data.user.country=${userCountry.orEmpty()}") DiagnosticLogger.logDebug(TAG, "login data.data.user.region=${userRegion.orEmpty()}") DiagnosticLogger.logDebug(TAG, "login account-id sha256 present=${!accountIdHash.isNullOrBlank()} prefix=${accountIdHash?.take(10).orEmpty()}...")
Log.i( TAG, "Login OK region=${candidate.code} endpoint=${candidate.baseUrl} tokenFound=true tokenPrefix=${tokenPrefix(token)}" ) DiagnosticLogger.logDebug(TAG, "login ok region=${candidate.code} tokenPrefix=${tokenPrefix(token)}") return LoginResult( token = token, region = candidate.code, accountIdHash = accountIdHash, userId = userId, userCountry = userCountry, userRegion = userRegion ) }
val ex = LibreLinkUpHttpException(status, errorText) lastError = ex Log.w( TAG, "Login failed endpoint=${candidate.baseUrl} region=${candidate.code} status=$status" ) DiagnosticLogger.logError( TAG, "login failed endpoint=${candidate.baseUrl} region=${candidate.code} status=$status attemptId=$loginAttemptId try=${index + 1}/${candidates.size} error=${maskSensitive(errorText)}" )
if (status == 430 || status == 429) throw ex }
throw lastError ?: LibreLinkUpException("Logowanie do LibreLinkUp nie powiodlo sie") }
open suspend fun getConnections(region: String, token: String, accountIdHash: String?): Response<JsonObject> { val baseUrl = baseUrlForRegion(region) val endpoint = "/llu/connections"
dlog("Token blank=${token.isBlank()}") dlog("Token length=${token.length}") dlog("Token prefix=${token.take(10)}...") dlog("Account-Id present=${!accountIdHash.isNullOrBlank()} prefix=${accountIdHash?.take(10).orEmpty()}...") dlog("Calling getConnections with Authorization header") DiagnosticStatus.setLastEndpoint(endpoint)
Log.d( TAG, "getConnections: region=$region baseUrl=$baseUrl endpoint=$endpoint tokenPresent=${token.isNotBlank()} tokenPrefix=${tokenPrefix(token)} authorizationSet=${("Bearer $token").startsWith("Bearer ")}" ) DiagnosticLogger.logDebug(TAG, "getConnections region=$region baseUrl=$baseUrl tokenPrefix=${tokenPrefix(token)}")
val response = createService(baseUrl).getConnections("Bearer $token", accountIdHash.orEmpty()) Log.d( TAG, "getConnections response: status=${response.code()} success=${response.isSuccessful} body=${maskSensitive(response.body()?.toString().orEmpty())}" ) if (!response.isSuccessful) { DiagnosticStatus.setGetConnections("HTTP ${response.code()}") DiagnosticLogger.logError(TAG, "getConnections failed HTTP ${response.code()} region=$region endpoint=$endpoint tokenPrefix=${tokenPrefix(token)}") } else { DiagnosticStatus.setGetConnections("OK") } return response }
open suspend fun getLatestGraph(region: String, token: String, patientId: String, accountIdHash: String?): Response<JsonObject> { val baseUrl = baseUrlForRegion(region) val endpoint = "/llu/connections/$patientId/graph"
Log.d(TAG, "Token is blank=${token.isBlank()}") Log.d(TAG, "Token length=${token.length}") Log.d(TAG, "Token prefix=${tokenPrefix(token)}") Log.d(TAG, "Account-Id present=${!accountIdHash.isNullOrBlank()} prefix=${accountIdHash?.take(10).orEmpty()}...") DiagnosticStatus.setLastEndpoint(endpoint)
Log.d( TAG, "getLatestGraph: region=$region baseUrl=$baseUrl endpoint=$endpoint patientId=$patientId tokenPresent=${token.isNotBlank()} tokenPrefix=${tokenPrefix(token)} authorizationSet=${("Bearer $token").startsWith("Bearer ")}" ) DiagnosticLogger.logDebug(TAG, "getLatestGraph region=$region endpoint=$endpoint patientId=$patientId tokenPrefix=${tokenPrefix(token)}")
val response = createService(baseUrl).getLatestGraph("Bearer $token", accountIdHash.orEmpty(), patientId) val status = response.code() if (!response.isSuccessful) { DiagnosticStatus.setGetLatestGraph("HTTP $status") val errorText = runCatching { response.errorBody()?.string().orEmpty() }.getOrDefault("") Log.w( TAG, "getLatestGraph HTTP $status: region=$region endpoint=$endpoint patientId=$patientId error=${maskSensitive(errorText)}" ) DiagnosticLogger.logError(TAG, "getLatestGraph failed HTTP $status region=$region endpoint=$endpoint patientId=$patientId body=${maskSensitive(errorText)}") } else { DiagnosticStatus.setGetLatestGraph("OK") } Log.d( TAG, "getLatestGraph response: status=$status success=${response.isSuccessful} body=${maskSensitive(response.body()?.toString().orEmpty())}" ) return response }
private fun createService(baseUrl: String): LibreLinkUpApiService { val headerInterceptor = Interceptor { chain -> val originalRequest = chain.request() dlog("Authorization BEFORE build = ${maskAuthorization(originalRequest.header("Authorization"))}") val requestBuilder = originalRequest.newBuilder() .header("Accept", "application/json") .header("Content-Type", "application/json") .header("product", productHeader) .header("version", versionHeader) .header("cache-control", "no-cache") .header("connection", "Keep-Alive") .header("User-Agent", "LibreDisplay/1.0 (Android)")
var request = requestBuilder.build() dlog("Authorization AFTER build = ${maskAuthorization(request.header("Authorization"))}")
// Safety net: preserve Authorization if it was present before newBuilder().build(). val authorizationBefore = originalRequest.header("Authorization") if (!authorizationBefore.isNullOrBlank() && request.header("Authorization").isNullOrBlank()) { request = request.newBuilder().header("Authorization", authorizationBefore).build() dlog("Authorization restored from original request") dlog("Authorization AFTER restore = ${maskAuthorization(request.header("Authorization"))}") }
dlog("FINAL REQUEST HEADERS") request.headers.names().sorted().forEach { val value = if (it.equals("Authorization", ignoreCase = true)) { maskAuthorization(request.header(it)) } else { request.header(it) } dlog("$it=$value") }
return@Interceptor chain.proceed(request) }
val networkDebugInterceptor = Interceptor { chain -> val request = chain.request() val headersToLog = listOf( "Authorization", "Accept", "Content-Type", "product", "version", "User-Agent", "cache-control", "connection", "Account-Id", "account-id" )
Log.d(TAG, "=====================") Log.d(TAG, "FINAL REQUEST") Log.d(TAG, "=====================") Log.d(TAG, "URL=${request.url}") Log.d(TAG, "METHOD=${request.method}") Log.d(TAG, "FINAL REQUEST HEADERS") headersToLog.forEach { name -> val value = request.header(name) val display = if (name.equals("Authorization", ignoreCase = true) && !value.isNullOrBlank()) { if (value.startsWith("Bearer ")) "Bearer ${value.removePrefix("Bearer ").take(10)}..." else "${value.take(10)}..." } else { value ?: "<MISSING>" } Log.d(TAG, "$name=$display") } request.headers.names().sorted().forEach { name -> val value = if (name.equals("Authorization", ignoreCase = true)) { maskAuthorization(request.header(name)) } else { request.header(name).orEmpty() } Log.d(TAG, "$name=$value") }
val response = chain.proceed(request) val responseBodyPreview = runCatching { response.peekBody(1024 * 1024).string() } .getOrDefault("<UNAVAILABLE>")
Log.d(TAG, "=====================") Log.d(TAG, "FINAL RESPONSE") Log.d(TAG, "=====================") Log.d(TAG, "status=${response.code}") Log.d(TAG, "headers=") response.headers.names().sorted().forEach { name -> Log.d(TAG, "$name=${response.header(name).orEmpty()}") } Log.d(TAG, "body=$responseBodyPreview")
return@Interceptor response }
val logging = HttpLoggingInterceptor().apply { level = HttpLoggingInterceptor.Level.BASIC }
val client = OkHttpClient.Builder() .addInterceptor(headerInterceptor) .addInterceptor(logging) .addInterceptor(networkDebugInterceptor) .build()
return Retrofit.Builder() .baseUrl(baseUrl) .client(client) .addConverterFactory(GsonConverterFactory.create()) .build() .create(LibreLinkUpApiService::class.java) }
private fun baseUrlForRegion(regionCode: String): String = when (regionCode.uppercase()) { "EU2" -> "https://api-eu2.libreview.io/" "US" -> "https://api-us.libreview.io/" "DE" -> "https://api-de.libreview.io/" "FR" -> "https://api-fr.libreview.io/" else -> "https://api-eu.libreview.io/" }
private fun regionCandidates(regionCode: String): List<RegionCandidate> { return when (regionCode.uppercase()) { "EU" -> listOf( RegionCandidate("EU", "https://api-eu.libreview.io/"), RegionCandidate("EU2", "https://api-eu2.libreview.io/") ) else -> listOf(RegionCandidate(regionCode.uppercase(), baseUrlForRegion(regionCode))) } }
private fun extractToken(body: JsonObject): String? { val probePaths = listOf( listOf("data", "authTicket", "token"), listOf("data", "data", "authTicket", "token"), listOf("data", "token"), listOf("token") )
val traces = probePaths.map { path -> readPathTrace(body, path) } traces.forEach { t -> DiagnosticLogger.logDebug(TAG, "READ: ${t.path} -> ${if (t.found) "SUCCESS" else "NULL"}${t.details}") }
val configuredPath = "root.data.data.authTicket.token" val configured = traces.firstOrNull { it.path == configuredPath } if (configured?.found == true) { return configured.value }
val failed = traces.joinToString(separator = "; ") { "${it.path}=${if (it.found) "FOUND" else "NOT_FOUND"}" } DiagnosticLogger.logError(TAG, "FAILED TOKEN PATHS: $failed") return null }
private fun logLoginResponseStructure(body: JsonObject) { try { val rootKeys = body.keySet().sorted() val data = getNodeAtPath(body, listOf("data")) val dataData = getNodeAtPath(body, listOf("data", "data")) val dataDataData = getNodeAtPath(body, listOf("data", "data", "data")) val authTicket = getNodeAtPath(body, listOf("data", "data", "authTicket")) val token = getNodeAtPath(body, listOf("data", "data", "authTicket", "token")) val user = getNodeAtPath(body, listOf("data", "data", "user")) val actualAuthTicketPath = if (authTicket?.isJsonObject == true) "data.data.authTicket" else "<not found>" val actualTokenPath = if (token?.isJsonPrimitive == true && token.asJsonPrimitive.isString) "data.data.authTicket.token" else "<not found>" val actualUserPath = if (user?.isJsonObject == true) "data.data.user" else "<not found>"
Log.d(TAG, "Login response keys: root=$rootKeys data=${keyList(data)} data.data=${keyList(dataData)} data.data.data=${keyList(dataDataData)} authTicket=${keyList(authTicket)} user=${keyList(user)}") DiagnosticLogger.logDebug(TAG, "login keys root=$rootKeys") DiagnosticLogger.logDebug(TAG, "login keys data=${keyList(data)}") DiagnosticLogger.logDebug(TAG, "login keys data.data=${keyList(dataData)}") DiagnosticLogger.logDebug(TAG, "login keys data.data.data=${keyList(dataDataData)}") DiagnosticLogger.logDebug(TAG, "login authTicket actualPath=$actualAuthTicketPath keys=${keyList(authTicket)} present=${authTicket?.isJsonObject == true}") DiagnosticLogger.logDebug(TAG, "login token actualPath=$actualTokenPath present=${token?.isJsonPrimitive == true && token.asJsonPrimitive.isString}") DiagnosticLogger.logDebug(TAG, "login user actualPath=$actualUserPath keys=${keyList(user)} present=${user?.isJsonObject == true}")
// Full structural dump (depth-limited) so parser regressions can be diagnosed without guessing paths. DiagnosticLogger.logDebug(TAG, "login tree begin") dumpJsonTree(path = "root", element = body, level = 0, maxDepth = 5) DiagnosticLogger.logDebug(TAG, "login tree end")
DiagnosticLogger.logDebug(TAG, "login full-path tree begin") dumpJsonTreePaths(path = "root", element = body, level = 0, maxDepth = 5) DiagnosticLogger.logDebug(TAG, "login full-path tree end")
val tokenLikeFields = mutableListOf<FoundField>() findAllMatchingKeys( element = body, currentPath = "root", targetKeys = setOf("token", "authTicket", "ticket", "jwt", "accessToken", "auth", "bearer", "authorization"), out = tokenLikeFields ) if (tokenLikeFields.isEmpty()) { DiagnosticLogger.logDebug(TAG, "login token-search FOUND: <none>") } else { tokenLikeFields.sortedBy { it.path }.forEach { field -> val meta = buildString { append("type=${field.type}") if (field.length != null) append(" length=${field.length}") if (!field.prefix.isNullOrBlank()) append(" prefix=${field.prefix}") } DiagnosticLogger.logDebug(TAG, "FOUND TOKEN-LIKE FIELD path=${field.path} $meta") } }
val userLikeFields = mutableListOf<FoundField>() findAllMatchingKeys( element = body, currentPath = "root", targetKeys = setOf("user", "authTicket", "patient", "connections"), out = userLikeFields ) if (userLikeFields.isEmpty()) { DiagnosticLogger.logDebug(TAG, "login entity-search FOUND: <none>") } else { userLikeFields.sortedBy { it.path }.forEach { field -> DiagnosticLogger.logDebug(TAG, "FOUND ENTITY FIELD path=${field.path} type=${field.type}") } } } catch (e: Exception) { Log.e(TAG, "Error logging response structure", e) } }
private data class FoundField( val path: String, val type: String, val length: Int? = null, val prefix: String? = null )
private data class ReadTrace( val path: String, val found: Boolean, val value: String? = null, val details: String = "" )
private fun readPathTrace(body: JsonObject, path: List<String>): ReadTrace { var current: JsonElement = body val printablePath = "root.${path.joinToString(".")}" for (key in path) { if (!current.isJsonObject) { return ReadTrace(printablePath, found = false, details = " (encountered non-object before '$key')") } val next = current.asJsonObject.get(key) ?: return ReadTrace(printablePath, found = false) current = next } if (current.isJsonPrimitive && current.asJsonPrimitive.isString) { val value = current.asString val prefix = if (value.isNotBlank()) "${value.take(10)}..." else "" return ReadTrace(printablePath, found = true, value = value, details = " (type=String length=${value.length} prefix=$prefix)") } return ReadTrace(printablePath, found = false, details = " (value not String)") }
private fun dumpJsonTree(path: String, element: JsonElement, level: Int, maxDepth: Int) { val indent = " ".repeat(level) if (level >= maxDepth) { DiagnosticLogger.logDebug(TAG, "$indent$path -> <max-depth>") return }
when { element.isJsonObject -> { val obj = element.asJsonObject DiagnosticLogger.logDebug(TAG, "$indent$path -> object keys=${obj.keySet().sorted()}") obj.entrySet().sortedBy { it.key }.forEach { (key, value) -> dumpJsonTree(path = "$path.$key", element = value, level = level + 1, maxDepth = maxDepth) } } element.isJsonArray -> { val array = element.asJsonArray DiagnosticLogger.logDebug(TAG, "$indent$path -> array size=${array.size()}") val previewCount = minOf(3, array.size()) for (i in 0 until previewCount) { dumpJsonTree(path = "$path[$i]", element = array[i], level = level + 1, maxDepth = maxDepth) } if (array.size() > previewCount) { DiagnosticLogger.logDebug(TAG, "$indent$path[...] -> ${array.size() - previewCount} more items") } } else -> { val type = if (element.isJsonPrimitive) { val p = element.asJsonPrimitive when { p.isString -> "string" p.isNumber -> "number" p.isBoolean -> "boolean" else -> "primitive" } } else if (element.isJsonNull) { "null" } else { "value" } DiagnosticLogger.logDebug(TAG, "$indent$path -> $type") } } }
private fun dumpJsonTreePaths(path: String, element: JsonElement, level: Int, maxDepth: Int) { if (level >= maxDepth) { DiagnosticLogger.logDebug(TAG, "$path") return } DiagnosticLogger.logDebug(TAG, path) when { element.isJsonObject -> { element.asJsonObject.entrySet().sortedBy { it.key }.forEach { (key, value) -> dumpJsonTreePaths(path = "$path.$key", element = value, level = level + 1, maxDepth = maxDepth) } } element.isJsonArray -> { val arr = element.asJsonArray val preview = minOf(3, arr.size()) for (i in 0 until preview) { dumpJsonTreePaths(path = "$path[$i]", element = arr[i], level = level + 1, maxDepth = maxDepth) } } } }
private fun findAllMatchingKeys( element: JsonElement, currentPath: String, targetKeys: Set<String>, out: MutableList<FoundField> ) { if (element.isJsonObject) { val obj = element.asJsonObject obj.entrySet().forEach { (key, value) -> val nextPath = "$currentPath.$key" if (targetKeys.any { it.equals(key, ignoreCase = true) }) { out += FoundField( path = nextPath, type = describeType(value), length = value.takeIf { it.isJsonPrimitive && it.asJsonPrimitive.isString }?.asString?.length, prefix = value.takeIf { it.isJsonPrimitive && it.asJsonPrimitive.isString }?.asString?.take(10)?.plus("...") ) } findAllMatchingKeys(value, nextPath, targetKeys, out) } } else if (element.isJsonArray) { element.asJsonArray.forEachIndexed { index, item -> findAllMatchingKeys(item, "$currentPath[$index]", targetKeys, out) } } }
private fun describeType(element: JsonElement): String { if (element.isJsonObject) return "Object" if (element.isJsonArray) return "Array" if (!element.isJsonPrimitive) return "Unknown" val p = element.asJsonPrimitive return when { p.isString -> "String" p.isNumber -> "Number" p.isBoolean -> "Boolean" else -> "Primitive" } }
private fun getNodeAtPath(body: JsonObject, path: List<String>): JsonElement? { var current: JsonElement = body for (key in path) { if (!current.isJsonObject) return null current = current.asJsonObject.get(key) ?: return null } return current }
private fun extractString(body: JsonObject, path: List<String>): String? { var current: JsonElement = body for (key in path) { if (!current.isJsonObject) return null current = current.asJsonObject.get(key) ?: return null } return if (current.isJsonPrimitive && current.asJsonPrimitive.isString) current.asString else null }
private fun getAvailableFields(body: JsonObject): String { return try { val fields = mutableListOf<String>()
// Root level fields body.keySet().forEach { key -> val value = body.get(key) fields.add(if (value.isJsonObject) "$key{...}" else key) }
// Try to get nested fields from data val dataElement = body.get("data") if (dataElement != null) { if (dataElement.isJsonObject) { dataElement.asJsonObject.keySet().forEach { key -> val value = dataElement.asJsonObject.get(key) fields.add(if (value.isJsonObject) "data.$key{...}" else "data.$key") } val payload = dataElement.asJsonObject.get("data") if (payload != null && payload.isJsonObject) { payload.asJsonObject.keySet().forEach { key -> val value = payload.asJsonObject.get(key) fields.add(if (value.isJsonObject) "data.data.$key{...}" else "data.data.$key") } val nestedPayload = payload.asJsonObject.get("data") if (nestedPayload != null && nestedPayload.isJsonObject) { nestedPayload.asJsonObject.keySet().forEach { key -> val value = nestedPayload.asJsonObject.get(key) fields.add(if (value.isJsonObject) "data.data.data.$key{...}" else "data.data.data.$key") } } } } else if (dataElement.isJsonArray) { fields.add("data[]") val firstObj = dataElement.asJsonArray.firstOrNull { it.isJsonObject } if (firstObj != null) { firstObj.asJsonObject.keySet().forEach { key -> fields.add("data[].$key") } } } }
fields.joinToString(", ") } catch (e: Exception) { "unknown" } }
private fun keyList(element: JsonElement?): List<String> { if (element == null) return emptyList() return when { element.isJsonObject -> element.asJsonObject.keySet().sorted() element.isJsonArray -> { val firstObject = element.asJsonArray.firstOrNull { it.isJsonObject } if (firstObject != null) { firstObject.asJsonObject.keySet().sorted() } else { emptyList() } } else -> emptyList() } }
private fun tokenPrefix(token: String): String = if (token.isBlank()) "" else "${token.take(10)}..."
private fun dlog(message: String) { Log.d(TAG, message) DiagnosticLogger.logDebug(TAG, message) }
private fun maskAuthorization(value: String?): String { if (value.isNullOrBlank()) return "<MISSING>" return if (value.startsWith("Bearer ")) { "Bearer ${value.removePrefix("Bearer ").take(10)}..." } else { "${value.take(10)}..." } }
private fun sha256Hex(value: String): String { val digest = MessageDigest.getInstance("SHA-256").digest(value.toByteArray(Charsets.UTF_8)) return digest.joinToString(separator = "") { byte -> "%02x".format(byte) } }
private fun maskEmail(email: String): String { val trimmed = email.trim() if (trimmed.isBlank() || !trimmed.contains("@")) return if (trimmed.isBlank()) "<blank>" else trimmed.take(3) + "..." val parts = trimmed.split("@", limit = 2) val localPrefix = parts[0].take(2) return if (localPrefix.isBlank()) "***@${parts[1]}" else "$localPrefix***@${parts[1]}" }
private fun maskSensitive(raw: String): String { if (raw.isBlank()) return raw var masked = raw val jsonSecrets = Regex("(?i)(\"(?:token|accesstoken|jwttoken|password|authorization)\"\\s*:\\s*\")[^\"]*(\")") masked = jsonSecrets.replace(masked, "$1***$2") val bearerSecrets = Regex("(?i)Bearer\\s+[A-Za-z0-9._-]+") masked = bearerSecrets.replace(masked, "Bearer ***") return masked }
private fun maskLoginRawResponse(raw: String): String { if (raw.isBlank()) return raw var masked = raw val tokenAndPassword = Regex("(?i)(\"(?:token|password)\"\\s*:\\s*\")[^\"]*(\")") masked = tokenAndPassword.replace(masked, "$1***MASKED***$2") return masked }
private fun extractResponseStatus(body: JsonObject): Int? { val rawStatus = body.get("status") ?: return null if (!rawStatus.isJsonPrimitive) return null val primitive = rawStatus.asJsonPrimitive return when { primitive.isNumber -> primitive.asInt primitive.isString -> primitive.asString.toIntOrNull() else -> null } }
private fun extractInt(body: JsonObject, path: List<String>): Int? { var current: JsonElement = body for (key in path) { if (!current.isJsonObject) return null current = current.asJsonObject.get(key) ?: return null } if (!current.isJsonPrimitive) return null val p = current.asJsonPrimitive return when { p.isNumber -> p.asInt p.isString -> p.asString.toIntOrNull() else -> null } }
private fun extractApiErrorMessage(body: JsonObject): String? { return extractString(body, listOf("error", "message")) ?: extractString(body, listOf("data", "message")) ?: extractString(body, listOf("message")) }
private fun isLogicalLoginFailure(apiStatus: Int?, apiErrorMessage: String?): Boolean { val normalizedMessage = apiErrorMessage?.trim().orEmpty() if (apiStatus != null && apiStatus !in setOf(0, 1, 200)) return true if (normalizedMessage.isBlank()) return false return !setOf("ok", "success").contains(normalizedMessage.lowercase()) }
private fun mapLogicalLoginFailureMessage(apiStatus: Int?, apiErrorMessage: String?): String { val message = apiErrorMessage?.trim().orEmpty() val lower = message.lowercase() return when { lower.contains("incorrect username/password") || lower.contains("invalid") || lower.contains("wrong") -> { "Nieprawidlowe dane logowania LibreLinkUp. Sprawdz email i haslo." } lower.contains("locked") || lower.contains("lockout") || lower.contains("too many") -> { "Serwer LibreLinkUp odrzucil logowanie z powodu zbyt wielu prob. Ponow probe recznie pozniej." } else -> { "Logowanie odrzucone przez API LibreLinkUp (status=${apiStatus ?: -1}, message=${if (message.isBlank()) "<brak>" else message})." } } }
private fun toLoginRequestJson(request: LoginRequest, maskPassword: Boolean, maskEmailValue: Boolean): String { val obj = JsonObject() obj.addProperty("email", if (maskEmailValue) maskEmail(request.email) else request.email) obj.addProperty("password", if (maskPassword) "***MASKED***" else request.password) return obj.toString() }
private fun appendLoginHistory(entry: String) { synchronized(loginHistoryLock) { loginRequestHistory += entry if (loginRequestHistory.size > 100) { loginRequestHistory.removeAt(0) } } }
private fun markSeenIncorrectUsernamePassword(loginAttemptId: String) { synchronized(loginHistoryLock) { seenIncorrectUsernamePassword = true appendLoginHistory("STATE attemptId=$loginAttemptId observed=incorrect username/password") } }
private fun maybeReportLoginStateChanged(loginAttemptId: String) { val snapshot: List<String> synchronized(loginHistoryLock) { if (!seenIncorrectUsernamePassword || seenHttp430AfterIncorrectReported) return seenHttp430AfterIncorrectReported = true snapshot = loginRequestHistory.toList() } DiagnosticLogger.logError(TAG, "LOGIN STATE CHANGED: observed 'incorrect username/password' and later HTTP 430 in one app run. attemptId=$loginAttemptId") snapshot.forEachIndexed { index, line -> DiagnosticLogger.logError(TAG, "LOGIN HISTORY [$index] $line") } }
