// Public method for testing fun extractResponseStatusForTest(body: JsonObject): Int? = extractResponseStatus(body) }
data class LoginResult( val token: String, val region: String, val accountIdHash: String? = null, val userId: String? = null, val userCountry: String? = null, val userRegion: String? = null )
data class RegionCandidate( val code: String, val baseUrl: String )
